import json
import boto3

sns = boto3.client('sns')

def lambda_handler(event, context):
    message_content = event['message']
    topic_arn = event['topicArn']
    
    # Publish message to SNS topic
    sns.publish(TopicArn=topic_arn, Message=json.dumps(message_content))